/**
 * Order pricing module.
 *
 * Computes the total price of an order: item subtotal, discounts, VAT, and
 * currency-aware rounding. The public surface is `computePrice`, the
 * `PricingFacade`, and the option/type exports; everything else is internal
 * machinery.
 */

export interface OrderItem {
  name: string;
  unitPrice: number;
  quantity: number;
}

export type Currency = "GBP" | "EUR" | "USD";

export interface Order {
  items: OrderItem[];
  currency: Currency;
  loyaltyMember: boolean;
}

// ---------------------------------------------------------------------------
// Money values
// ---------------------------------------------------------------------------

class Money {
  constructor(
    private readonly amount: number,
    private readonly currency: Currency,
  ) {}

  get value(): number {
    return this.amount;
  }

  plus(other: Money): Money {
    if (other.currency !== this.currency) {
      throw new Error("cannot add across currencies without conversion");
    }
    return new Money(this.amount + other.amount, this.currency);
  }

  times(factor: number): Money {
    return new Money(this.amount * factor, this.currency);
  }

  round(rounding: (v: number) => number): Money {
    return new Money(rounding(this.amount), this.currency);
  }
}

// ---------------------------------------------------------------------------
// Discount strategies
// ---------------------------------------------------------------------------

interface DiscountStrategy {
  applies(order: Order): boolean;
  apply(subtotal: number): number;
}

const discountStrategies: DiscountStrategy[] = [
  {
    applies: (order) => order.items.reduce((sum, i) => sum + i.quantity, 0) >= 10,
    apply: (subtotal) => subtotal * 0.9,
  },
  {
    applies: (order) => new Set(order.items.map((i) => i.name)).size >= 3,
    apply: (subtotal) => subtotal * 0.98,
  },
  {
    applies: (order) => order.loyaltyMember,
    apply: (subtotal) => subtotal * 0.95,
  },
];

// ---------------------------------------------------------------------------
// Pricing options
// ---------------------------------------------------------------------------

export interface PricingHooks {
  beforeStage?(stageName: string): void;
  afterStage?(stageName: string, runningTotal: number): void;
}

export interface PricingOptions {
  vatRate?: number;
  /** Only half-up rounding is implemented; the enum anticipates bankers'. */
  roundingMode?: "half-up";
  /** Reserved for localised price formatting. */
  locale?: string;
  /** Observability hooks invoked around every pipeline stage. */
  hooks?: PricingHooks;
}

const DEFAULT_PRICING_OPTIONS: Required<Omit<PricingOptions, "hooks">> = {
  vatRate: 0.2,
  roundingMode: "half-up",
  locale: "en-GB",
};

function resolveOptions(
  options?: PricingOptions,
): Required<Omit<PricingOptions, "hooks">> & { hooks: PricingHooks } {
  return {
    ...DEFAULT_PRICING_OPTIONS,
    ...(options ?? {}),
    hooks: options?.hooks ?? {},
  };
}

// ---------------------------------------------------------------------------
// Rounding
// ---------------------------------------------------------------------------

function roundToTwoDecimals(value: number): number {
  return Math.round(value * 100) / 100;
}

// ---------------------------------------------------------------------------
// Pricing pipeline
// ---------------------------------------------------------------------------

function computeOrderPrice(
  order: Order,
  options: Required<Omit<PricingOptions, "hooks">> & { hooks: PricingHooks },
): number {
  const hooks = options.hooks;

  hooks.beforeStage?.("subtotal");
  let price = new Money(0, order.currency);
  for (const item of order.items) {
    price = price.plus(
      new Money(item.unitPrice * item.quantity, order.currency),
    );
  }
  hooks.afterStage?.("subtotal", price.value);

  hooks.beforeStage?.("discount");
  let discounted = price.value;
  for (const strategy of discountStrategies) {
    if (strategy.applies(order)) {
      discounted = strategy.apply(discounted);
    }
  }
  price = new Money(discounted, order.currency);
  hooks.afterStage?.("discount", price.value);

  hooks.beforeStage?.("tax");
  price = price.times(1 + options.vatRate);
  hooks.afterStage?.("tax", price.value);

  hooks.beforeStage?.("rounding");
  price = price.round(roundToTwoDecimals);
  hooks.afterStage?.("rounding", price.value);

  return price.value;
}

export class PricingFacade {
  private readonly options: Required<Omit<PricingOptions, "hooks">> & {
    hooks: PricingHooks;
  };

  constructor(options?: PricingOptions) {
    this.options = resolveOptions(options);
  }

  price(order: Order): number {
    return computeOrderPrice(order, this.options);
  }
}

export function computePrice(order: Order, options?: PricingOptions): number {
  return new PricingFacade(options).price(order);
}

